        'body-md': ['16px', { lineHeight: '150%', fontWeight: '400' }],
        'body-sm': ['14px', { lineHeight: '150%', fontWeight: '400' }],
        'body-xs': ['12px', { lineHeight: '150%', fontWeight: '400' }],

        // Action - Inter
